mapper.update:
UPDATE ESG.TB_MSDS_INFO_UNIT
SET
    UNIT_NM = #{unitNm},
    UNIT_DESC = #{unitDesc},
    ORD_SEQ = #{ordSeq},
    USE_YN = #{useYn},
    UPDATED_AT = now(),
    UPDATED_BY = #{updatedBy}
WHERE UNIT_ID = #{unitId}
  AND comp_id = #{compId}

mapper.delete:
UPDATE ESG.TB_MSDS_INFO_UNIT
SET
    USE_YN = 'N',
    UPDATED_AT = now(),
    UPDATED_BY = #{updatedBy}
WHERE UNIT_ID = #{unitId}
  AND comp_id = #{compId}
